changeSet.sql:
DECLARE @authorId BIGINT;

SELECT TOP 1 @authorId = ur.user_id
FROM user_role ur
JOIN role r ON ur.role_id = r.id
WHERE r.name = 'moderator';

INSERT INTO quiz (author_id, title, instructions)
VALUES
    (@authorId, 'Relational Fundamentals', 'Answer all questions regarding the basic structure of RDBMS and ACID properties.'),
    (@authorId, 'SQL/Schema Design', 'This exam tests your ability to write DDL/DML statements and design normalized schemas.'),
    (@authorId, 'Final Assessment', 'Demonstrate your knowledge of indexing strategies and query performance tuning.');
